def is_valid_circular_tic_tac_toe(arr, N):
    # Helper to get element with circular wrapping
    def get_val(r, c):
        return arr[(r % N) * N + (c % N)]

    # 1. Check Rows
    for r in range(N):
        row_vals = [get_val(r, c) for c in range(N)]
        if len(set(row_vals)) == 1: # All same
            return False

    # 2. Check Columns
    for c in range(N):
        col_vals = [get_val(r, c) for r in range(N)]
        if len(set(col_vals)) == 1:
            return False

    # 3. Check 2x2 Sub-grids (including wrapping)
    for r in range(N):
        for c in range(N):
            # Define 2x2 starting at (r, c)
            sub_grid = [
                get_val(r, c),     get_val(r, c+1),
                get_val(r+1, c),   get_val(r+1, c+1)
            ]
            if len(set(sub_grid)) == 1:
                return False

    return True
Time Complexity: $O(N^2)$
Space Complexity: $O(N)$
